head.b:skin:
:root{
--bg:#0f0f0f;--bg2:#141414;--bg3:#1a1a1a;
--txt:#ffffff;--txt2:#a0a0a0;--txt3:#606060;
--gold:#d4af37;--gold2:#f0c84a;--gold3:#b8941f;
--wa:#25D366;--wa2:#1ebe5d;
--glass:rgba(255,255,255,0.04);--gborder:rgba(255,255,255,0.07);
--gborder2:rgba(212,175,55,0.18);
--shadow:0 0 50px rgba(212,175,55,0.12);
--r:14px;--r2:22px;
--ease:cubic-bezier(0.25,0.46,0.45,0.94);
--fD:'Montserrat',sans-serif;--fB:'Space Grotesk',sans-serif;--fU:'Inter',sans-serif;
}
*,*::before,*::after{margin:0;padding:0;box-sizing:border-box;}
html{scroll-behavior:smooth;overflow-x:hidden;}
body{background:var(--bg);color:var(--txt);font-family:var(--fB);overflow-x:hidden;line-height:1.6;-webkit-font-smoothing:antialiased;}
::-webkit-scrollbar{width:3px;}
::-webkit-scrollbar-track{background:var(--bg);}
::-webkit-scrollbar-thumb{background:linear-gradient(var(--gold),var(--gold2));border-radius:2px;}
img{max-width:100%;height:auto;}
a{text-decoration:none;color:inherit;}
#ga-progress{position:fixed;top:0;left:0;height:2px;background:linear-gradient(90deg,var(--gold),var(--gold2),#fff8dc);z-index:99999;width:0%;box-shadow:0 0 8px rgba(212,175,55,0.6);}
#ga-loader{position:fixed;inset:0;background:var(--bg);z-index:999999;display:flex;align-items:center;justify-content:center;flex-direction:column;gap:24px;transition:opacity .6s ease;}
#ga-loader.hide{opacity:0;pointer-events:none;}
.ldr-wrap{position:relative;}
.ldr-img{width:88px;height:88px;border-radius:50%;object-fit:cover;border:2px solid var(--gold);animation:ldrSpin 3s linear infinite;filter:drop-shadow(0 0 18px rgba(212,175,55,0.5));}
.ldr-ring{position:absolute;inset:-8px;border-radius:50%;border:1px solid transparent;border-top:1px solid var(--gold);border-right:1px solid var(--gold2);animation:ldrSpin 1.4s linear infinite reverse;}
@keyframes ldrSpin{to{transform:rotate(360deg);}}
.ldr-name{font-family:var(--fD);font-size:1.5rem;font-weight:900;letter-spacing:5px;background:linear-gradient(135deg,var(--gold),var(--gold2));-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;}
.ldr-sub{font-size:.68rem;letter-spacing:4px;text-transform:uppercase;color:var(--txt3);}
.ldr-bar{width:170px;height:1px;background:var(--bg3);overflow:hidden;}
.ldr-fill{height:100%;background:linear-gradient(90deg,var(--gold),var(--gold2));animation:ldrFill 2.3s ease forwards;}
@keyframes ldrFill{0%{width:0%}100%{width:100%}}
#ga-cursor-dot{position:fixed;width:6px;height:6px;background:var(--gold);border-radius:50%;pointer-events:none;z-index:99998;transform:translate(-50%,-50%);}
#ga-cursor-ring{position:fixed;width:36px;height:36px;border:1px solid rgba(212,175,55,0.4);border-radius:50%;pointer-events:none;z-index:99997;transform:translate(-50%,-50%);transition:width .25s,height .25s,border-color .25s;}
body.chov #ga-cursor-ring{width:54px;height:54px;border-color:rgba(212,175,55,0.75);}
#ga-nav{position:fixed;top:0;left:0;right:0;z-index:9900;padding:0 5%;height:68px;display:flex;align-items:center;justify-content:space-between;transition:all .4s var(--ease);}
#ga-nav.scrolled{background:rgba(10,10,10,0.96);backdrop-filter:blur(22px);border-bottom:1px solid var(--gborder);height:56px;}
.nlogo-w{display:flex;align-items:center;gap:10px;}
.nlogo-img{width:36px;height:36px;border-radius:50%;object-fit:cover;border:1px solid var(--gborder2);transition:all .3s;}
.nlogo-w:hover .nlogo-img{border-color:var(--gold);box-shadow:0 0 14px rgba(212,175,55,0.4);}
.nlogo-t{font-family:var(--fD);font-size:1.1rem;font-weight:900;letter-spacing:3px;background:linear-gradient(135deg,var(--gold),var(--gold2));-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;}
.nav-links{display:flex;align-items:center;gap:28px;list-style:none;}
.nav-links a{font-family:var(--fU);font-size:.78rem;font-weight:500;color:var(--txt2);letter-spacing:1px;text-transform:uppercase;transition:color .3s;position:relative;padding-bottom:3px;}
.nav-links a::after{content:'';position:absolute;bottom:0;left:0;width:0;height:1px;background:var(--gold);transition:width .3s;}
.nav-links a:hover{color:var(--gold);}
.nav-links a:hover::after{width:100%;}
.nav-cta{background:linear-gradient(135deg,var(--gold),var(--gold3)) !important;color:#000 !important;-webkit-text-fill-color:#000 !important;padding:8px 20px !important;border-radius:50px !important;font-weight:700 !important;box-shadow:0 4px 16px rgba(212,175,55,0.3) !important;}
.nav-cta::after{display:none !important;}
.nav-cta:hover{transform:translateY(-2px) !important;box-shadow:0 8px 28px rgba(212,175,55,0.5) !important;}
.nav-r{display:flex;align-items:center;gap:10px;}
.n-theme{width:36px;height:36px;background:var(--glass);border:1px solid var(--gborder);border-radius:50%;display:flex;align-items:center;justify-content:center;color:var(--gold);cursor:pointer;transition:all .3s;font-size:.82rem;}
.n-theme:hover{background:var(--gold);color:#000;}
.n-burger{display:none;flex-direction:column;gap:5px;cursor:pointer;padding:4px;}
.n-burger span{display:block;width:22px;height:2px;background:var(--gold);border-radius:1px;transition:all .3s;}
.n-burger.open span:nth-child(1){transform:rotate(45deg) translate(5px,5px);}
.n-burger.open span:nth-child(2){opacity:0;}
.n-burger.open span:nth-child(3){transform:rotate(-45deg) translate(5px,-5px);}
.mob-nav{position:fixed;inset:0;background:rgba(8,8,8,0.98);backdrop-filter:blur(28px);z-index:9800;display:flex;align-items:center;justify-content:center;flex-direction:column;gap:26px;transform:translateX(100%);transition:transform .42s var(--ease);}
.mob-nav.open{transform:translateX(0);}
.mob-nav a{font-family:var(--fD);font-size:1.7rem;font-weight:800;letter-spacing:3px;text-transform:uppercase;color:var(--txt2);transition:color .3s;}
.mob-nav a:hover{color:var(--gold);}
.mob-wa{background:var(--wa) !important;color:#fff !important;-webkit-text-fill-color:#fff !important;padding:13px 28px !important;border-radius:50px !important;font-size:.95rem !important;display:flex;align-items:center;gap:8px;box-shadow:0 8px 28px rgba(37,211,102,0.4);}
#hero{min-height:100vh;display:flex;align-items:center;justify-content:center;position:relative;overflow:hidden;padding:128px 5% 88px;}
.hero-bg{position:absolute;inset:0;z-index:0;}
.h-grid{position:absolute;inset:0;background-image:linear-gradient(rgba(212,175,55,0.032) 1px,transparent 1px),linear-gradient(90deg,rgba(212,175,55,0.032) 1px,transparent 1px);background-size:54px 54px;}
.h-orb-a{position:absolute;width:620px;height:620px;background:radial-gradient(circle,rgba(212,175,55,0.09) 0%,transparent 68%);top:-8%;right:-5%;animation:orbF 9s ease-in-out infinite;border-radius:50%;}
.h-orb-b{position:absolute;width:400px;height:400px;background:radial-gradient(circle,rgba(212,175,55,0.07) 0%,transparent 68%);bottom:8%;left:6%;animation:orbF 7s ease-in-out infinite reverse;border-radius:50%;}
@keyframes orbF{0%,100%{transform:translate(0,0) scale(1);}33%{transform:translate(22px,-16px) scale(1.04);}66%{transform:translate(-16px,22px) scale(.97);}}
.h-pts{position:absolute;inset:0;pointer-events:none;}
.hpt{position:absolute;border-radius:50%;background:var(--gold);animation:ptF linear infinite;opacity:0;}
@keyframes ptF{0%{transform:translateY(0) translateX(0);opacity:0;}10%{opacity:.6;}85%{opacity:.25;}100%{transform:translateY(-110vh) translateX(55px);opacity:0;}}
.h-content{position:relative;z-index:2;text-align:center;max-width:920px;margin:0 auto;}
.h-badge{display:inline-flex;align-items:center;gap:9px;background:var(--glass);border:1px solid var(--gborder2);border-radius:50px;padding:7px 20px;font-size:.7rem;font-family:var(--fU);letter-spacing:2.5px;text-transform:uppercase;color:var(--gold);margin-bottom:28px;backdrop-filter:blur(12px);opacity:0;animation:rUp .8s ease .3s forwards;}
.h-bdot{width:6px;height:6px;background:var(--gold);border-radius:50%;animation:bDot 1.5s ease-in-out infinite;}
@keyframes bDot{0%,100%{box-shadow:0 0 0 0 rgba(212,175,55,.5);}50%{box-shadow:0 0 0 5px rgba(212,175,55,0);}}
.h-brand-show{display:flex;align-items:center;justify-content:center;gap:16px;margin-bottom:24px;opacity:0;animation:rUp .8s ease .4s forwards;}
.h-brand-img{width:66px;height:66px;border-radius:50%;object-fit:cover;border:2px solid var(--gborder2);animation:bGlow 3s ease-in-out infinite;}
@keyframes bGlow{0%,100%{box-shadow:0 0 22px rgba(212,175,55,0.25);}50%{box-shadow:0 0 44px rgba(212,175,55,0.55);}}
.h-brand-nm{font-family:var(--fD);font-size:clamp(1.1rem,2.5vw,1.8rem);font-weight:900;letter-spacing:4px;background:linear-gradient(135deg,var(--gold),var(--gold2));-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;}
.h-brand-sub{font-size:.68rem;letter-spacing:3px;color:var(--txt2);text-transform:uppercase;margin-top:2px;}
.h1{font-family:var(--fD);font-size:clamp(2.7rem,7vw,6.8rem);font-weight:900;line-height:1.0;letter-spacing:-2px;margin-bottom:20px;opacity:0;animation:rUp .8s ease .55s forwards;}
.h1 .l1{display:block;color:var(--txt);}
.h1 .l2-wrap{display:block;min-height:1.15em;}.h1 .l2{display:inline;background:linear-gradient(135deg,var(--gold),var(--gold2),#ffe97a);-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;border-right:3px solid var(--gold);animation:blnk .65s step-end infinite;padding-right:2px;}
.h-sub{font-size:clamp(.92rem,1.7vw,1.18rem);color:var(--txt2);max-width:560px;margin:0 auto 32px;line-height:1.85;opacity:0;animation:rUp .8s ease .7s forwards;}
.h-typing{color:var(--gold);}
@keyframes blnk{0%,100%{border-color:var(--gold);}50%{border-color:transparent;}}
.h-btns{display:flex;gap:12px;justify-content:center;flex-wrap:wrap;margin-bottom:52px;opacity:0;animation:rUp .8s ease .88s forwards;}
.h-stats{display:flex;justify-content:center;gap:40px;flex-wrap:wrap;opacity:0;animation:rUp .8s ease 1.05s forwards;}
.h-sn{font-family:var(--fD);font-size:2.3rem;font-weight:900;background:linear-gradient(135deg,var(--gold),var(--gold2));-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;line-height:1;}
.h-sl{font-size:.7rem;color:var(--txt3);letter-spacing:2px;text-transform:uppercase;margin-top:3px;}
@keyframes rUp{from{opacity:0;transform:translateY(30px);}to{opacity:1;transform:translateY(0);}}
.btn-pri{display:inline-flex;align-items:center;gap:9px;background:linear-gradient(135deg,var(--gold),var(--gold3));color:#000;font-family:var(--fD);font-weight:700;font-size:.83rem;letter-spacing:1px;text-transform:uppercase;padding:14px 32px;border-radius:50px;transition:all .3s;box-shadow:0 6px 22px rgba(212,175,55,0.3);position:relative;overflow:hidden;}
.btn-pri::before{content:'';position:absolute;inset:0;background:linear-gradient(135deg,var(--gold2),var(--gold));opacity:0;transition:opacity .3s;}
.btn-pri:hover{transform:translateY(-3px);box-shadow:0 13px 42px rgba(212,175,55,0.46);}
.btn-pri:hover::before{opacity:1;}
.btn-pri span{position:relative;z-index:1;}
.btn-sec{display:inline-flex;align-items:center;gap:9px;background:transparent;color:var(--txt);font-family:var(--fD);font-weight:600;font-size:.83rem;letter-spacing:1px;text-transform:uppercase;padding:13px 32px;border-radius:50px;border:1px solid var(--gborder);transition:all .3s;}
.btn-sec:hover{border-color:var(--gold);color:var(--gold);transform:translateY(-3px);}
.btn-wa{display:inline-flex;align-items:center;gap:9px;background:var(--wa);color:#fff;font-family:var(--fD);font-weight:700;font-size:.83rem;padding:13px 30px;border-radius:50px;transition:all .3s;box-shadow:0 6px 22px rgba(37,211,102,0.28);}
.btn-wa:hover{background:var(--wa2);transform:translateY(-3px);box-shadow:0 13px 42px rgba(37,211,102,0.42);}
section{padding:88px 5%;position:relative;}
.s-tag{display:inline-flex;align-items:center;gap:9px;color:var(--gold);font-family:var(--fU);font-size:.7rem;font-weight:600;letter-spacing:3px;text-transform:uppercase;margin-bottom:13px;}
.s-tag::before{content:'';display:block;width:18px;height:1px;background:var(--gold);}
.s-title{font-family:var(--fD);font-size:clamp(1.9rem,4.3vw,3.6rem);font-weight:900;line-height:1.1;letter-spacing:-1px;margin-bottom:14px;}
.s-title .g{color:var(--gold);}
.s-sub{font-size:.97rem;color:var(--txt2);max-width:570px;line-height:1.85;}
.s-div{width:48px;height:2px;background:linear-gradient(90deg,var(--gold),transparent);margin-bottom:26px;border-radius:1px;}
.reveal{opacity:0;transform:translateY(34px);transition:opacity .68s ease,transform .68s ease;}
.reveal.on{opacity:1;transform:translateY(0);}
.reveal-l{opacity:0;transform:translateX(-34px);transition:opacity .68s ease,transform .68s ease;}
.reveal-l.on{opacity:1;transform:translateX(0);}
.reveal-r{opacity:0;transform:translateX(34px);transition:opacity .68s ease,transform .68s ease;}
.reveal-r.on{opacity:1;transform:translateX(0);}
.stagger>*{opacity:0;transform:translateY(26px);transition:opacity .5s ease,transform .5s ease;}
.stagger.on>*:nth-child(1){opacity:1;transform:none;}
.stagger.on>*:nth-child(2){opacity:1;transform:none;transition-delay:.1s;}
.stagger.on>*:nth-child(3){opacity:1;transform:none;transition-delay:.2s;}
.stagger.on>*:nth-child(4){opacity:1;transform:none;transition-delay:.3s;}
.stagger.on>*:nth-child(5){opacity:1;transform:none;transition-delay:.4s;}
.stagger.on>*:nth-child(6){opacity:1;transform:none;transition-delay:.5s;}
.stagger.on>*:nth-child(7){opacity:1;transform:none;transition-delay:.6s;}
.stagger.on>*:nth-child(8){opacity:1;transform:none;transition-delay:.7s;}
.stagger.on>*:nth-child(9){opacity:1;transform:none;transition-delay:.8s;}
.mq-strip{background:linear-gradient(135deg,rgba(212,175,55,0.07),rgba(212,175,55,0.03));border-top:1px solid var(--gborder2);border-bottom:1px solid var(--gborder2);padding:16px 0;overflow:hidden;white-space:nowrap;}
.mq-inner{display:inline-flex;gap:46px;animation:mqScroll 20s linear infinite;}
.mq-item{display:inline-flex;align-items:center;gap:10px;font-family:var(--fD);font-size:.78rem;font-weight:700;letter-spacing:2px;text-transform:uppercase;color:var(--txt2);}
.mq-item i{color:var(--gold);font-size:.72rem;}
@keyframes mqScroll{0%{transform:translateX(0);}100%{transform:translateX(-50%);}}
#services{background:var(--bg2);}
.svc-hd{text-align:center;margin-bottom:56px;}
.svc-hd .s-sub{margin:0 auto;}
.svc-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(265px,1fr));gap:16px;max-width:1200px;margin:0 auto;}
.svc-c{background:var(--glass);border:1px solid var(--gborder);border-radius:var(--r);padding:30px 24px;position:relative;overflow:hidden;transition:all .4s var(--ease);}
.svc-c::before{content:'';position:absolute;inset:0;background:linear-gradient(135deg,rgba(212,175,55,0.07),transparent);opacity:0;transition:opacity .4s;}
.svc-c::after{content:'';position:absolute;bottom:0;left:0;right:0;height:2px;background:linear-gradient(90deg,var(--gold),var(--gold2));transform:scaleX(0);transform-origin:left;transition:transform .4s var(--ease);}
.svc-c:hover{border-color:var(--gborder2);transform:translateY(-7px);box-shadow:var(--shadow);}
.svc-c:hover::before{opacity:1;}
.svc-c:hover::after{transform:scaleX(1);}
.svc-icon{width:50px;height:50px;background:linear-gradient(135deg,rgba(212,175,55,0.13),rgba(212,175,55,0.04));border:1px solid var(--gborder2);border-radius:11px;display:flex;align-items:center;justify-content:center;font-size:1.3rem;color:var(--gold);margin-bottom:16px;transition:all .3s;}
.svc-c:hover .svc-icon{background:linear-gradient(135deg,var(--gold),var(--gold3));color:#000;border-color:transparent;transform:scale(1.1) rotate(-5deg);}
.svc-n{font-family:var(--fD);font-size:1rem;font-weight:700;margin-bottom:7px;}
.svc-d{font-size:.85rem;color:var(--txt2);line-height:1.7;}
.svc-num{position:absolute;top:16px;right:20px;font-family:var(--fD);font-size:3.2rem;font-weight:900;color:rgba(212,175,55,0.045);line-height:1;pointer-events:none;}
#portfolio{background:var(--bg);}
.port-hd{display:flex;justify-content:space-between;align-items:flex-end;margin-bottom:46px;flex-wrap:wrap;gap:16px;}
.p-filters{display:flex;gap:9px;flex-wrap:wrap;}
.flt-b{background:transparent;border:1px solid var(--gborder);color:var(--txt2);font-family:var(--fU);font-size:.73rem;letter-spacing:1.5px;text-transform:uppercase;padding:6px 16px;border-radius:50px;cursor:pointer;transition:all .3s;}
.flt-b:hover,.flt-b.active{background:var(--gold);border-color:var(--gold);color:#000;font-weight:700;}
.port-grid{display:grid;grid-template-columns:repeat(12,1fr);gap:16px;max-width:1200px;margin:0 auto;}
.port-item{border-radius:var(--r2);overflow:hidden;position:relative;cursor:pointer;background:var(--bg2);border:1px solid var(--gborder);transition:all .4s var(--ease);}
.port-item:hover{border-color:var(--gborder2);box-shadow:var(--shadow);}
.port-item:nth-child(1){grid-column:span 7;}
.port-item:nth-child(2){grid-column:span 5;}
.port-item:nth-child(3){grid-column:span 4;}
.port-item:nth-child(4){grid-column:span 4;}
.port-item:nth-child(5){grid-column:span 4;}
.port-img{width:100%;aspect-ratio:16/10;overflow:hidden;background:var(--bg3);}
.port-img-in{width:100%;height:100%;display:flex;align-items:center;justify-content:center;position:relative;transition:transform .6s var(--ease);background:linear-gradient(135deg,var(--bg3),var(--bg));}
.port-icon{font-size:3.5rem;color:rgba(212,175,55,0.14);}
.port-item:hover .port-img-in{transform:scale(1.06);}.port-img-in img{width:100%;height:100%;object-fit:cover;transition:transform .6s var(--ease);display:block;}.port-item:hover .port-img-in img{transform:scale(1.06);}
.port-ov{position:absolute;inset:0;background:linear-gradient(to top,rgba(0,0,0,.88) 0%,rgba(0,0,0,.38) 40%,transparent);opacity:0;transition:opacity .4s;display:flex;align-items:flex-end;padding:20px;}
.port-item:hover .port-ov{opacity:1;}
.port-cat{font-size:.66rem;font-family:var(--fU);letter-spacing:2px;text-transform:uppercase;color:var(--gold);margin-bottom:2px;}
.port-nm{font-family:var(--fD);font-size:.97rem;font-weight:700;}
.port-lnk{position:absolute;top:13px;right:13px;width:38px;height:38px;background:var(--gold);border-radius:50%;display:flex;align-items:center;justify-content:center;color:#000;opacity:0;transform:scale(.8);transition:all .3s;font-size:.82rem;}
.port-item:hover .port-lnk{opacity:1;transform:scale(1);}
.bpc-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(285px,1fr));gap:20px;max-width:1200px;margin:46px auto 0;}
.bpc{background:var(--glass);border:1px solid var(--gborder);border-radius:var(--r);overflow:hidden;display:block;transition:all .4s var(--ease);}
.bpc:hover{border-color:var(--gborder2);transform:translateY(-7px);box-shadow:var(--shadow);}
.bpc-img{width:100%;aspect-ratio:16/9;overflow:hidden;background:var(--bg3);display:flex;align-items:center;justify-content:center;}
.bpc-img img{width:100%;height:100%;object-fit:cover;transition:transform .5s;}
.bpc:hover .bpc-img img{transform:scale(1.06);}
.bpc-body{padding:18px;}
.bpc-lbl{display:inline-block;background:rgba(212,175,55,0.12);color:var(--gold);font-size:.66rem;font-weight:700;letter-spacing:2px;text-transform:uppercase;padding:3px 9px;border-radius:4px;margin-bottom:8px;}
.bpc-title{font-family:var(--fD);font-size:.97rem;font-weight:700;margin-bottom:6px;line-height:1.4;}
.bpc-snip{font-size:.82rem;color:var(--txt2);line-height:1.7;}
.bpc-ft{display:flex;justify-content:space-between;align-items:center;margin-top:13px;padding-top:13px;border-top:1px solid var(--gborder);}
.bpc-dt{font-size:.7rem;color:var(--txt3);}
#about{background:var(--bg2);}
.about-w{display:grid;grid-template-columns:1fr 1fr;gap:66px;align-items:center;max-width:1200px;margin:0 auto;}
.about-vis{position:relative;}
.about-card{border-radius:var(--r2);overflow:hidden;aspect-ratio:4/5;background:var(--bg3);border:1px solid var(--gborder);position:relative;}
.about-in{width:100%;height:100%;display:flex;align-items:center;justify-content:center;flex-direction:column;gap:14px;background:linear-gradient(135deg,var(--bg3),var(--bg));padding:30px;}
.about-img-main{width:120px;height:120px;border-radius:50%;object-fit:cover;border:3px solid var(--gold);box-shadow:0 0 38px rgba(212,175,55,0.28);animation:aGlow 3s ease-in-out infinite;}
@keyframes aGlow{0%,100%{box-shadow:0 0 38px rgba(212,175,55,0.28);}50%{box-shadow:0 0 72px rgba(212,175,55,0.58);}}
.about-logo-img{width:150px;object-fit:contain;opacity:.82;filter:drop-shadow(0 0 14px rgba(212,175,55,0.35));}
.about-wm{position:absolute;font-family:var(--fD);font-size:8rem;font-weight:900;color:rgba(212,175,55,0.025);letter-spacing:-5px;pointer-events:none;user-select:none;}
.about-badge{position:absolute;bottom:-16px;right:-16px;background:linear-gradient(135deg,var(--gold),var(--gold3));border-radius:var(--r);padding:16px 20px;text-align:center;box-shadow:0 16px 46px rgba(212,175,55,0.3);}
.ab-n{font-family:var(--fD);font-size:2.3rem;font-weight:900;color:#000;line-height:1;}
.ab-l{font-size:.62rem;font-weight:700;color:rgba(0,0,0,.65);letter-spacing:1px;text-transform:uppercase;}
.about-txt{color:var(--txt2);font-size:.93rem;line-height:1.9;margin-bottom:24px;}
.af-grid{display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:32px;}
.af{display:flex;align-items:flex-start;gap:10px;}
.af-i{width:28px;height:28px;min-width:28px;background:rgba(212,175,55,0.09);border:1px solid var(--gborder2);border-radius:7px;display:flex;align-items:center;justify-content:center;color:var(--gold);font-size:.72rem;margin-top:2px;}
.af-t strong{display:block;font-size:.85rem;font-weight:600;}
.af-t span{font-size:.76rem;color:var(--txt2);}
.cnt-row{display:grid;grid-template-columns:repeat(4,1fr);gap:16px;max-width:1200px;margin:52px auto 0;}
.cnt-c{background:var(--glass);border:1px solid var(--gborder);border-radius:var(--r);padding:24px 16px;text-align:center;transition:all .3s;}
.cnt-c:hover{border-color:var(--gborder2);transform:translateY(-4px);box-shadow:var(--shadow);}
.cnt-n{font-family:var(--fD);font-size:2.5rem;font-weight:900;background:linear-gradient(135deg,var(--gold),var(--gold2));-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;line-height:1;margin-bottom:6px;}
.cnt-l{font-size:.7rem;color:var(--txt2);letter-spacing:1.5px;text-transform:uppercase;}
#process{background:var(--bg);}
.proc-hd{text-align:center;margin-bottom:66px;}
.proc-hd .s-sub{margin:0 auto;}
.proc-steps{display:grid;grid-template-columns:repeat(4,1fr);max-width:1080px;margin:0 auto;position:relative;}
.proc-line{position:absolute;top:47px;left:12.5%;right:12.5%;height:1px;background:linear-gradient(90deg,transparent,rgba(212,175,55,.22),rgba(212,175,55,.22),transparent);}
.proc-step{text-align:center;padding:0 16px;}
.ps-w{position:relative;display:inline-block;margin-bottom:20px;}
.ps-n{width:94px;height:94px;background:var(--bg2);border:1px solid var(--gborder);border-radius:50%;display:flex;align-items:center;justify-content:center;font-family:var(--fD);font-size:1.35rem;font-weight:900;color:var(--gold);transition:all .38s;margin:0 auto;position:relative;z-index:1;}
.proc-step:hover .ps-n{background:linear-gradient(135deg,var(--gold),var(--gold3));color:#000;border-color:transparent;transform:scale(1.1);box-shadow:0 0 38px rgba(212,175,55,0.36);}
.ps-badge{position:absolute;top:-6px;right:-6px;width:24px;height:24px;background:var(--gold);border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:.62rem;color:#000;border:2px solid var(--bg);}
.ps-t{font-family:var(--fD);font-size:1.05rem;font-weight:800;margin-bottom:7px;}
.ps-d{font-size:.83rem;color:var(--txt2);line-height:1.75;}
#testimonials{background:var(--bg2);overflow:hidden;}
.test-hd{text-align:center;margin-bottom:48px;}
.test-slider{max-width:840px;margin:0 auto;position:relative;overflow:hidden;}
.test-track{display:flex;transition:transform .5s var(--ease);}
.test-c{min-width:100%;background:var(--glass);border:1px solid var(--gborder);border-radius:var(--r2);padding:40px;position:relative;overflow:hidden;}
.test-c::before{content:'"';position:absolute;top:12px;left:32px;font-family:var(--fD);font-size:8rem;font-weight:900;color:rgba(212,175,55,0.07);line-height:1;pointer-events:none;}
.test-stars{display:flex;gap:3px;color:var(--gold);margin-bottom:16px;}
.test-txt{font-size:1.02rem;line-height:1.9;color:var(--txt2);margin-bottom:22px;position:relative;z-index:1;}
.test-auth{display:flex;align-items:center;gap:12px;}
.test-av{width:48px;height:48px;border-radius:50%;background:linear-gradient(135deg,var(--gold),var(--gold3));display:flex;align-items:center;justify-content:center;font-family:var(--fD);font-weight:900;font-size:.95rem;color:#000;flex-shrink:0;}
.test-an{font-family:var(--fD);font-weight:700;font-size:.9rem;margin-bottom:1px;}
.test-ar{font-size:.76rem;color:var(--txt2);}
.sl-ctrl{display:flex;justify-content:center;align-items:center;gap:13px;margin-top:26px;}
.sl-btn{width:40px;height:40px;border-radius:50%;background:var(--glass);border:1px solid var(--gborder);color:var(--txt);display:flex;align-items:center;justify-content:center;cursor:pointer;transition:all .3s;font-size:.82rem;}
.sl-btn:hover{background:var(--gold);border-color:var(--gold);color:#000;}
.sl-dots{display:flex;gap:6px;}
.sl-dot{width:7px;height:7px;border-radius:50%;background:var(--gborder);cursor:pointer;transition:all .3s;}
.sl-dot.active{background:var(--gold);width:20px;border-radius:4px;}
#technology{background:var(--bg);}
.tech-hd{text-align:center;margin-bottom:46px;}
.tech-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(108px,1fr));gap:13px;max-width:940px;margin:0 auto;}
.tech-item{background:var(--glass);border:1px solid var(--gborder);border-radius:var(--r);padding:24px 12px;text-align:center;transition:all .3s;}
.tech-item:hover{border-color:var(--gborder2);transform:translateY(-5px);box-shadow:var(--shadow);}
.tech-ic{font-size:1.9rem;color:var(--gold);margin-bottom:8px;display:block;transition:transform .3s;}
.tech-item:hover .tech-ic{transform:scale(1.2) rotate(-5deg);}
.tech-nm{font-family:var(--fU);font-size:.68rem;font-weight:600;letter-spacing:1.5px;text-transform:uppercase;color:var(--txt2);}
#wa-cta{background:var(--bg2);}
.wa-box{max-width:780px;margin:0 auto;background:linear-gradient(135deg,rgba(37,211,102,0.09),rgba(37,211,102,0.03));border:1px solid rgba(37,211,102,0.2);border-radius:var(--r2);padding:56px 42px;text-align:center;position:relative;overflow:hidden;}
.wa-box::before{content:'';position:absolute;top:-40%;left:-40%;width:180%;height:180%;background:radial-gradient(circle,rgba(37,211,102,0.05) 0%,transparent 60%);animation:waPls 4s ease-in-out infinite;pointer-events:none;}
@keyframes waPls{0%,100%{transform:scale(1);opacity:.5;}50%{transform:scale(1.08);opacity:1;}}
.wa-big-i{font-size:3.8rem;color:var(--wa);margin-bottom:16px;display:block;animation:waFl 2s ease-in-out infinite;}
@keyframes waFl{0%,100%{transform:translateY(0);}50%{transform:translateY(-10px);}}
.wa-t{font-family:var(--fD);font-size:clamp(1.6rem,3.8vw,2.7rem);font-weight:900;margin-bottom:13px;letter-spacing:-1px;}
.wa-s{font-size:.97rem;color:var(--txt2);margin-bottom:30px;line-height:1.8;}
.btn-wa-big{display:inline-flex;align-items:center;gap:11px;background:var(--wa);color:#fff;font-family:var(--fD);font-weight:800;font-size:1.02rem;letter-spacing:1px;padding:17px 42px;border-radius:50px;transition:all .3s;box-shadow:0 13px 42px rgba(37,211,102,0.36);position:relative;z-index:1;}
.btn-wa-big:hover{background:var(--wa2);transform:translateY(-4px);box-shadow:0 20px 52px rgba(37,211,102,0.5);}
.wa-note{margin-top:16px;font-size:.76rem;color:rgba(255,255,255,.32);position:relative;z-index:1;}
#contact{background:var(--bg);}
.con-w{display:grid;grid-template-columns:1fr 1fr;gap:52px;max-width:1080px;margin:0 auto;}
.con-items{display:flex;flex-direction:column;gap:14px;margin-top:26px;}
.con-item{display:flex;align-items:flex-start;gap:13px;background:var(--glass);border:1px solid var(--gborder);border-radius:var(--r);padding:16px 20px;text-decoration:none;color:inherit;transition:all .3s;}
.con-item:hover{border-color:var(--gborder2);transform:translateX(5px);box-shadow:var(--shadow);}
.ci-ic{width:40px;height:40px;min-width:40px;background:rgba(212,175,55,0.09);border:1px solid var(--gborder2);border-radius:9px;display:flex;align-items:center;justify-content:center;color:var(--gold);font-size:.95rem;}
.ci-t strong{display:block;font-weight:700;font-size:.85rem;margin-bottom:1px;}
.ci-t span{font-size:.8rem;color:var(--txt2);}
.con-form{background:var(--glass);border:1px solid var(--gborder);border-radius:var(--r2);padding:32px;}
.con-form h3{font-family:var(--fD);font-size:1.25rem;font-weight:800;margin-bottom:20px;}
.fg{margin-bottom:16px;}
.fg label{display:block;font-size:.72rem;font-family:var(--fU);letter-spacing:1.5px;text-transform:uppercase;color:var(--txt2);margin-bottom:6px;}
.fg input,.fg textarea,.fg select{width:100%;background:rgba(255,255,255,0.027);border:1px solid var(--gborder);border-radius:8px;color:var(--txt);font-family:var(--fB);font-size:.9rem;padding:11px 15px;outline:none;transition:border-color .3s,box-shadow .3s;resize:vertical;}
.fg input:focus,.fg textarea:focus,.fg select:focus{border-color:var(--gold);box-shadow:0 0 0 3px rgba(212,175,55,0.08);}
.fg textarea{height:90px;}
.fg select option{background:var(--bg2);}
.f-sub-btn{width:100%;background:linear-gradient(135deg,var(--gold),var(--gold3));color:#000;font-family:var(--fD);font-weight:800;font-size:.87rem;letter-spacing:2px;text-transform:uppercase;padding:14px;border-radius:50px;border:none;cursor:pointer;transition:all .3s;box-shadow:0 7px 24px rgba(212,175,55,0.27);}
.f-sub-btn:hover{transform:translateY(-2px);box-shadow:0 13px 42px rgba(212,175,55,0.44);}
#ga-footer{background:var(--bg2);border-top:1px solid var(--gborder);}
.ft-top{padding:68px 5% 50px;display:grid;grid-template-columns:2fr 1fr 1fr 1fr;gap:42px;max-width:1200px;margin:0 auto;}
.ft-logo-w{display:flex;align-items:center;gap:10px;margin-bottom:13px;}
.ft-logo-i{width:40px;height:40px;border-radius:50%;object-fit:cover;border:1px solid var(--gborder2);}
.ft-logo-t{font-family:var(--fD);font-size:1.3rem;font-weight:900;letter-spacing:3px;background:linear-gradient(135deg,var(--gold),var(--gold2));-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;}
.ft-brand p{font-size:.85rem;color:var(--txt2);line-height:1.8;margin-bottom:20px;}
.ft-soc{display:flex;gap:9px;}
.soc-l{width:36px;height:36px;background:var(--glass);border:1px solid var(--gborder);border-radius:8px;display:flex;align-items:center;justify-content:center;color:var(--txt2);font-size:.86rem;transition:all .3s;}
.soc-l:hover{background:var(--gold);border-color:var(--gold);color:#000;transform:translateY(-3px);}
.ft-col h4{font-family:var(--fD);font-size:.78rem;font-weight:700;letter-spacing:2px;text-transform:uppercase;color:var(--txt);margin-bottom:16px;}
.ft-links{list-style:none;display:flex;flex-direction:column;gap:8px;}
.ft-links a{font-size:.83rem;color:var(--txt2);transition:color .3s;display:flex;align-items:center;gap:7px;}
.ft-links a::before{content:'';display:block;width:9px;height:1px;background:var(--gold);transition:width .3s;}
.ft-links a:hover{color:var(--gold);}
.ft-links a:hover::before{width:15px;}
.ft-btm{padding:18px 5%;border-top:1px solid var(--gborder);display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:13px;max-width:1200px;margin:0 auto;}
.ft-copy{font-size:.78rem;color:var(--txt3);}
.ft-copy span{color:var(--gold);}
.ft-pol{display:flex;gap:20px;}
.ft-pol a{font-size:.78rem;color:var(--txt3);transition:color .3s;}
.ft-pol a:hover{color:var(--gold);}
#wa-float{position:fixed;bottom:26px;right:26px;z-index:9500;display:flex;flex-direction:column;align-items:flex-end;gap:9px;}
.wa-bbl{background:#1a1a1a;border:1px solid rgba(37,211,102,0.3);color:var(--txt);font-size:.78rem;font-weight:600;padding:8px 13px;border-radius:16px 16px 4px 16px;white-space:nowrap;opacity:0;transform:translateX(16px) scale(.9);transition:all .3s;pointer-events:none;box-shadow:0 4px 16px rgba(0,0,0,.3);}
.wa-bbl.show{opacity:1;transform:translateX(0) scale(1);}
.wa-fbtn{width:56px;height:56px;background:var(--wa);border-radius:50%;display:flex;align-items:center;justify-content:center;color:#fff;font-size:1.4rem;box-shadow:0 6px 26px rgba(37,211,102,0.42);transition:all .3s;animation:waBP 3s ease-in-out infinite;}
@keyframes waBP{0%,100%{box-shadow:0 6px 26px rgba(37,211,102,0.42);}50%{box-shadow:0 6px 52px rgba(37,211,102,0.72);}}
.wa-fbtn:hover{transform:scale(1.1);background:var(--wa2);}
#bk-top{position:fixed;bottom:96px;right:26px;width:40px;height:40px;background:var(--glass);border:1px solid var(--gborder);border-radius:50%;display:flex;align-items:center;justify-content:center;color:var(--gold);cursor:pointer;z-index:9400;opacity:0;transform:translateY(16px);transition:all .3s;font-size:.82rem;backdrop-filter:blur(10px);}
#bk-top.show{opacity:1;transform:translateY(0);}
#bk-top:hover{background:var(--gold);color:#000;border-color:var(--gold);transform:translateY(-4px);}
.mob-bnav{display:none;position:fixed;bottom:0;left:0;right:0;z-index:9300;background:rgba(10,10,10,.96);backdrop-filter:blur(20px);border-top:1px solid var(--gborder);padding:9px 0 16px;}
.mbn{display:flex;justify-content:space-around;}
.mbn-i{display:flex;flex-direction:column;align-items:center;gap:2px;text-decoration:none;color:var(--txt2);transition:color .3s;}
.mbn-i i{font-size:1.1rem;}
.mbn-i span{font-size:.56rem;font-family:var(--fU);letter-spacing:1px;text-transform:uppercase;}
.mbn-i:hover,.mbn-i.act{color:var(--gold);}
body.lm{--bg:#f3f3f3;--bg2:#e9e9e9;--bg3:#ddd;--txt:#0f0f0f;--txt2:#555;--txt3:#888;--glass:rgba(0,0,0,0.04);--gborder:rgba(0,0,0,0.08);}
.post-pg-hd{padding:108px 5% 48px;max-width:760px;margin:0 auto;text-align:center;}
.post-pg-t{font-family:var(--fD);font-size:clamp(1.8rem,4.2vw,3.1rem);font-weight:900;line-height:1.1;letter-spacing:-1px;margin-bottom:16px;}
.post-pg-m{display:flex;justify-content:center;gap:16px;flex-wrap:wrap;font-size:.78rem;color:var(--txt2);margin-bottom:26px;}
.post-pg-m span{display:flex;align-items:center;gap:5px;}
.post-pg-m i{color:var(--gold);}
.post-thumb{max-width:860px;margin:0 auto 48px;padding:0 5%;}
.post-thumb img{width:100%;border-radius:var(--r2);}
.post-bdy{max-width:730px;margin:0 auto;padding:0 5% 68px;font-size:1rem;line-height:1.9;color:var(--txt2);}
.post-bdy h2,.post-bdy h3{font-family:var(--fD);color:var(--txt);margin:34px 0 13px;}
.post-bdy p{margin-bottom:17px;}
.post-bdy img{width:100%;border-radius:var(--r);margin:20px 0;}
.post-bdy a{color:var(--gold);}
@media(max-width:1024px){
.port-item:nth-child(1){grid-column:span 12;}
.port-item:nth-child(2){grid-column:span 12;}
.port-item:nth-child(3){grid-column:span 6;}
.port-item:nth-child(4){grid-column:span 6;}
.port-item:nth-child(5){grid-column:span 12;}
.about-w{grid-template-columns:1fr;gap:42px;}
.cnt-row{grid-template-columns:repeat(2,1fr);}
.ft-top{grid-template-columns:1fr 1fr;}
}
@media(max-width:768px){
section{padding:62px 5%;}
.nav-links{display:none;}
.n-burger{display:flex;}
.h-btns{flex-direction:column;align-items:center;}
.h-stats{gap:24px;}
.port-grid{grid-template-columns:1fr;}
.port-item:nth-child(n){grid-column:span 1;}
.proc-steps{grid-template-columns:1fr 1fr;gap:26px;}
.proc-line{display:none;}
.con-w{grid-template-columns:1fr;}
.ft-top{grid-template-columns:1fr;gap:26px;}
.ft-btm{flex-direction:column;text-align:center;}
#ga-cursor-dot,#ga-cursor-ring{display:none;}
.mob-bnav{display:block;}
.cnt-row{grid-template-columns:repeat(2,1fr);}
#bk-top{bottom:80px;}
#wa-float{bottom:80px;right:13px;}
}
@media(max-width:480px){
.proc-steps{grid-template-columns:1fr;}
.about-badge{right:0;bottom:-7px;}
.test-c{padding:26px 18px;}
}

body.script:
//
(function(){window.addEventListener('load',function(){setTimeout(function(){var l=document.getElementById('ga-loader');if(l){l.classList.add('hide');setTimeout(function(){l.style.display='none';},650);}},2400);});})();
(function(){var b=document.getElementById('ga-progress');if(!b)return;window.addEventListener('scroll',function(){var st=document.documentElement.scrollTop;var sh=document.documentElement.scrollHeight-document.documentElement.clientHeight;b.style.width=(st/sh*100)+'%';},{passive:true});})();
(function(){var dot=document.getElementById('ga-cursor-dot');var ring=document.getElementById('ga-cursor-ring');if(!dot||!ring)return;var rx=0,ry=0,mx=0,my=0;document.addEventListener('mousemove',function(e){mx=e.clientX;my=e.clientY;dot.style.left=mx+'px';dot.style.top=my+'px';},{passive:true});function ar(){rx+=(mx-rx)*.13;ry+=(my-ry)*.13;ring.style.left=rx+'px';ring.style.top=ry+'px';requestAnimationFrame(ar);}ar();document.querySelectorAll('a,button,.svc-c,.tech-item,.port-item,.cnt-c').forEach(function(el){el.addEventListener('mouseenter',function(){document.body.classList.add('chov');});el.addEventListener('mouseleave',function(){document.body.classList.remove('chov');});});})();
(function(){var nav=document.getElementById('ga-nav');if(!nav)return;window.addEventListener('scroll',function(){nav.classList.toggle('scrolled',window.scrollY>60);},{passive:true});})();
(function(){var btn=document.getElementById('nav-burger');var mn=document.getElementById('mob-nav');if(!btn||!mn)return;btn.addEventListener('click',function(){mn.classList.toggle('open');btn.classList.toggle('open');});})();
function cMN(){var mn=document.getElementById('mob-nav');var btn=document.getElementById('nav-burger');if(mn)mn.classList.remove('open');if(btn)btn.classList.remove('open');}
(function(){var c=document.getElementById('h-pts');if(!c)return;for(var i=0;i<16;i++){var p=document.createElement('div');p.className='hpt';var s=Math.random()*2.5+1;p.style.cssText='left:'+Math.random()*100+'%;top:'+(Math.random()*40+100)+'%;width:'+s+'px;height:'+s+'px;animation-duration:'+(Math.random()*13+9)+'s;animation-delay:'+(Math.random()*7)+'s;';c.appendChild(p);}})();
(function(){var el=document.getElementById('h-type');if(!el)return;var words=['Digital Experiences','Luxury Websites','Ecommerce Stores','Brand Identities','Premium Designs'];var wi=0,ci=0,del=false;function tick(){var w=words[wi];if(!del){el.textContent=w.substring(0,ci+1);ci++;if(ci===w.length){del=true;setTimeout(tick,2000);return;}}else{el.textContent=w.substring(0,ci-1);ci--;if(ci===0){del=false;wi=(wi+1)%words.length;}}setTimeout(tick,del?55:95);}setTimeout(tick,1900);})();
(function(){var done=[];function anim(el){var t=parseInt(el.getAttribute('data-t'));var start=performance.now();var dur=1700;function upd(now){var p=Math.min((now-start)/dur,1);var e=1-Math.pow(1-p,3);el.textContent=Math.round(e*t)+(t>=3?'+':'');if(p<1)requestAnimationFrame(upd);}requestAnimationFrame(upd);}var io=new IntersectionObserver(function(entries){entries.forEach(function(en){if(en.isIntersecting&&done.indexOf(en.target)===-1){done.push(en.target);anim(en.target);}});},{threshold:.5});document.querySelectorAll('.cval').forEach(function(el){io.observe(el);});})();
(function(){var io=new IntersectionObserver(function(entries){entries.forEach(function(en){if(en.isIntersecting)en.target.classList.add('on');});},{threshold:.1,rootMargin:'0px 0px -28px 0px'});document.querySelectorAll('.reveal,.reveal-l,.reveal-r,.stagger').forEach(function(el){io.observe(el);});})();
(function(){var track=document.getElementById('test-track');var dots=document.querySelectorAll('.sl-dot');var prev=document.getElementById('sl-prev');var next=document.getElementById('sl-next');if(!track)return;var cur=0,tot=dots.length;function go(i){cur=i;track.style.transform='translateX(-'+(i*100)+'%)';dots.forEach(function(d){d.classList.remove('active');});if(dots[i])dots[i].classList.add('active');}if(next)next.addEventListener('click',function(){go((cur+1)%tot);});if(prev)prev.addEventListener('click',function(){go((cur-1+tot)%tot);});dots.forEach(function(d){d.addEventListener('click',function(){go(parseInt(d.getAttribute('data-i')));});});setInterval(function(){go((cur+1)%tot);},5500);})();
(function(){var btn=document.getElementById('bk-top');if(!btn)return;window.addEventListener('scroll',function(){btn.classList.toggle('show',window.scrollY>400);},{passive:true});btn.addEventListener('click',function(e){e.preventDefault();window.scrollTo({top:0,behavior:'smooth'});});})();
(function(){var bbl=document.getElementById('wa-bbl');var fbtn=document.getElementById('wa-fbtn');if(!bbl)return;setTimeout(function(){bbl.classList.add('show');},3500);setTimeout(function(){bbl.classList.remove('show');},9000);if(fbtn){fbtn.addEventListener('mouseenter',function(){bbl.classList.add('show');});fbtn.addEventListener('mouseleave',function(){bbl.classList.remove('show');});}})();
(function(){var btn=document.getElementById('f-sub');if(!btn)return;btn.addEventListener('click',function(){var n=document.getElementById('c-name').value.trim();var e=document.getElementById('c-email').value.trim();var s=document.getElementById('c-service').value;var m=document.getElementById('c-msg').value.trim();if(!n||!m){alert('Please fill in your name and message.');return;}var t='Hello%20GA%20Istovia!%0A%0AName:%20'+encodeURIComponent(n)+'%0AEmail:%20'+encodeURIComponent(e)+'%0AService:%20'+encodeURIComponent(s)+'%0AMessage:%20'+encodeURIComponent(m);window.open('https://wa.me/255792207616?text='+t,'_blank');});})();
(function(){var btn=document.getElementById('theme-btn');if(!btn)return;var ic=btn.querySelector('i');btn.addEventListener('click',function(){document.body.classList.toggle('lm');if(document.body.classList.contains('lm')){ic.className='fas fa-moon';}else{ic.className='fas fa-sun';}});})();
(function(){document.querySelectorAll('.flt-b').forEach(function(btn){btn.addEventListener('click',function(){document.querySelectorAll('.flt-b').forEach(function(b){b.classList.remove('active');});btn.classList.add('active');});});})();
(function(){document.querySelectorAll('.btn-pri,.btn-wa-big').forEach(function(btn){btn.addEventListener('mousemove',function(e){var r=btn.getBoundingClientRect();var x=e.clientX-r.left-r.width/2;var y=e.clientY-r.top-r.height/2;btn.style.transform='translate('+x*.1+'px,'+y*.15+'px) translateY(-3px)';});btn.addEventListener('mouseleave',function(){btn.style.transform='';});});})();
